import { useState, useRef } from "react";

import Sidebar from './Sidebar';
import CanvasContainer from './CanvasContainer';
import RightSideBar from './RightSideBar'

function Main() {
    const canvasRef = useRef(null);
    s
    
    const [objects, setObjects] = useState([]);
    const [draggingId, setDraggingId] = useState(null);
    const [offset, setOffset] = useState({ x: 0, y: 0 });

    const [doubleClickedObjId, setDoubleClickedObjId] = useState('');

    function newObject() {
        setObjects(prev => [
            ...prev,
            { id: Date.now(), left: canvasRef.width, top: canvasRef.height, color: "green", radius: "50%"}
        ]);
    }

    function startDragging(id, e) {
        setDraggingId(id);

        const rect = e.target.getBoundingClientRect();

        setOffset({
            x: e.clientX - rect.left,
            y: e.clientY - rect.top
        });
    }

    function dragging(e) {
        if (!draggingId) return;

        const canvasRect = canvasRef.current.getBoundingClientRect();

        const objectSize = 80;

        let newLeft = e.clientX - canvasRect.left - offset.x;
        let newTop = e.clientY - canvasRect.top - offset.y;

        newLeft = Math.max(0, Math.min(newLeft, canvasRect.width - objectSize));
        newTop = Math.max(0, Math.min(newTop, canvasRect.height - objectSize));

        setObjects(prev =>
            prev.map(obj =>
                obj.id === draggingId
                    ? { ...obj, left: newLeft, top: newTop }
                    : obj
            )
        );
    }
    
    function stopDragging() {
        setDraggingId(null);
    }


    return (
        <div className="main">
            <Sidebar
                newObject={newObject}
                doubleClickedObjId={doubleClickedObjId}
                setObjects={setObjects}
                objects={objects}
            ></Sidebar>
            
            <CanvasContainer
                canvasRef={canvasRef} objects={objects} startDragging={startDragging} dragging={dragging} stopDragging={stopDragging}
                setDoubleClickedObjId={setDoubleClickedObjId}
            ></CanvasContainer>
            <RightSideBar></RightSideBar>
        </div>
    );
}

export default Main;
